import{c as t,a7 as e,y as o,B as a}from"./chunks/framework.3cjvm90C.js";const u=JSON.parse('{"title":"连续批处理（Continuous Batching）原理与应用优化","description":"详解 LLM 推理中连续批处理技术的演进原理及其如何通过迭代级调度最大化 GPU 吞吐量。","frontmatter":{"title":"连续批处理（Continuous Batching）原理与应用优化","description":"详解 LLM 推理中连续批处理技术的演进原理及其如何通过迭代级调度最大化 GPU 吞吐量。"},"headers":[],"relativePath":"inference/continue_batching.md","filePath":"inference/continue_batching.md","lastUpdated":1782447613000}'),g={name:"inference/continue_batching.md"};function i(s,n,r,c,l,h){return e(),o("div",null,[...n[0]||(n[0]=[a('<h1 id="连续批处理-continuous-batching-原理与应用优化" tabindex="-1">连续批处理（Continuous Batching）原理与应用优化 <a class="header-anchor" href="#连续批处理-continuous-batching-原理与应用优化" aria-label="Permalink to “连续批处理（Continuous Batching）原理与应用优化”">​</a></h1><p><strong>摘要</strong>：本文深入探讨大型语言模型（LLM）推理中的<strong>连续批处理（Continuous Batching）</strong> 技术。我们将从批处理策略的演进出发，结合注意力机制（Attention Mechanism）和 KV Cache 的基础，推导出连续批处理如何通过优化吞吐量来显著提升 LLM 的服务性能。</p><h2 id="背景-从静态批处理到连续批处理" tabindex="-1">背景：从静态批处理到连续批处理 <a class="header-anchor" href="#背景-从静态批处理到连续批处理" aria-label="Permalink to “背景：从静态批处理到连续批处理”">​</a></h2><p>GPU 专为高度并行计算负载设计，每秒可执行数万亿次浮点运算（FLOPs）。然而 LLMs 通常无法充分利用 GPU，因为大部分内存带宽消耗在加载模型参数上。批处理通过跨多个请求复用已加载的模型参数，有效缓解了这一瓶颈。</p><p><strong>静态批处理</strong>：服务器等待固定数量的请求到达后，将它们作为一个批次统一处理。缺陷在于批次中首个请求必须等待最后一个请求到达，且所有请求必须等待最慢的请求完成，造成 GPU 资源浪费。</p><p><strong>动态批处理</strong>：设置时间窗口，处理该时段内到达的所有请求。若批次提前达到规模上限则立即启动处理。这有助于平衡吞吐量与延迟，但批次中最长的请求仍决定整个批次的完成时间。</p><p><strong>连续批处理</strong>：允许批次中每个序列独立完成，并立即用新请求替换已完成序列。该技术采用迭代级调度策略，批次组成在每个解码迭代周期动态变化，从而最大化 GPU 占用率。主流推理框架如 vLLM、SGLang、TensorRT-LLM、LMDeploy 和 Hugging Face TGI 均已支持这一机制。</p><p>下面我们从 LLM 推理的底层机制出发，深入理解连续批处理的工作原理。</p><p>在使用像 Qwen、Claude 或其他 AI 聊天机器人时，用户通常会观察到这样的现象：模型生成<strong>第一个</strong> Token 需要一段短暂的时间，随后 Token 会以稳定且快速的节奏逐个显示在屏幕上。这种现象源于 LLM 的本质：它们是复杂的<strong>下一个 Token 预测器</strong>。LLM 首先需要处理完整的输入提示词（prompt）来生成第一个新的 Token，随后进入一个<strong>自回归（autoregressive）</strong> 循环，逐个生成后续 Token，直到模型决定终止生成。</p><p>这个生成过程的计算成本极高。每生成一个 Token，都需要将输入数据流经包含数十亿参数的模型网络。为了使这些模型在实际应用中具有实用性，尤其是在同时服务大量并发用户时，研究人员和工程师开发了一系列高效的推理优化技术。其中，最具影响力的优化之一就是<strong>连续批处理（Continuous Batching）</strong>。该技术通过并行处理多个对话，并在任一对话完成时立即用新的等待请求替换它，从而最大化 GPU 的利用率和整体吞吐量。</p><p>为了理解连续批处理的工作原理及其在高负载服务场景中的卓越效率，我们首先需要回顾 LLM 处理 Token 的基础知识。</p><h2 id="一、注意力机制-attention-mechanism" tabindex="-1">一、注意力机制（Attention Mechanism） <a class="header-anchor" href="#一、注意力机制-attention-mechanism" aria-label="Permalink to “一、注意力机制（Attention Mechanism）”">​</a></h2><p>注意力机制是 LLM 能够理解并生成连贯文本的核心。语言模型首先将输入文本切分为称为 <strong>Token</strong> 的片段（概念上可类比于&quot;单词&quot;，但一个词可能由多个 Token 构成）。对于每一个 Token 序列，网络都会计算并预测最有可能的下一个 Token。</p><p>网络中的许多操作是<strong>逐 Token（token-wise）</strong> 的，例如层归一化（Layer Normalization）或矩阵乘法，它们的输出仅依赖于当前 Token 的内容。然而，为了在序列中的 Token 之间建立语义联系，模型需要引入 Token 之间能够相互影响的操作——这就是注意力机制的作用。<strong>注意力层是序列中不同 Token 之间进行信息交互的唯一场所。</strong> 理解注意力机制，即是理解网络如何将序列中的 Token 连接起来。</p><p>让我们以单个输入提示词为例，观察这一过程是如何实际运作的。</p><h3 id="_1-预填充阶段-prefill-stage" tabindex="-1">1. 预填充阶段（Prefill Stage） <a class="header-anchor" href="#_1-预填充阶段-prefill-stage" aria-label="Permalink to “1. 预填充阶段（Prefill Stage）”">​</a></h3><p>考虑初始输入提示词 &quot;I am sure this project&quot;，它被分词为 7 个 Token：<code>[&lt;bos&gt;, I, am, sure, this, pro, ject]</code>。这里的 <code>&lt;bos&gt;</code>（Beginning of Sequence，序列开始）是一个特殊的 Token，用于标记新的对话的起点。</p><p>在网络内部，每个 Token 被表示为一个长度为 $d$（隐藏维度，Hidden Dimension）的向量。因此，这 $n=7$ 个输入 Token 构成了一个形状为 $(1, n, d)$ 的输入张量 $X$（其中 $1$ 为批大小）。</p><p>输入张量 $X$ 随后通过三个投影矩阵 $W_Q$、$W_K$ 和 $W_V$ 进行投影，分别生成<strong>查询状态（Query State）</strong> $Q$、<strong>键状态（Key State）</strong> $K$ 和<strong>值状态（Value State）</strong> $V$。它们的形状均为 $(1, n, A)$，其中 $A$ 是注意力头（Attention Head）的维度。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/proj_and_mul.png" alt="proj_and_mul.png" style="zoom:33%;"><p>注意力计算的核心步骤如下：</p><ol><li><strong>相似度计算：</strong> $Q$ 和 $K$ 的转置相乘（$QK^T$），用于测量序列中所有 Token 对之间的相似度（即关联性），生成一个形状为 $(1, n, n)$ 的得分张量。 <ul><li><strong>复杂度分析：</strong> 这一步是注意力机制计算成本的主要来源。计算 $QK^T$ 需要 $O(n^2d)$ 次操作，其时间复杂度与序列长度 $n$ 的<strong>平方</strong>成正比。</li></ul></li><li><strong>注意力掩码应用：</strong> 随后，对 $QK^T$ 应用一个<strong>布尔注意力掩码（Boolean Attention Mask）</strong>，以控制哪些 Token 可以交互。 <ul><li>在文本生成任务中，我们通常使用<strong>因果掩码（Causal Mask）</strong>。它强制要求每个 Token 只能关注（或影响）它自身及它之前的 Token。位置 $(i, j)$ 的掩码值为 $\\text{True}$ 表示 Token $j$ 可以影响 Token $i$。</li></ul></li></ol><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/masking_and_softmax.png" alt="masking_and_softmax.png" style="zoom:33%;"><ol start="3"><li><strong>最终输出：</strong> 在应用注意力掩码和逐行 Softmax 归一化后，将结果与值投影 $V$ 相乘，得到注意力层的输出。</li></ol><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/attention.png" alt="attention.png" style="zoom:33%;"><p>这个过程——将整个输入序列送入模型并计算下一个 Token 的预测分数——被称为<strong>预填充（Prefill）</strong>。由于 LLM 生成是自回归的，在这个阶段计算得到的许多中间结果可以被缓存和重用，从而为后续的 Token 生成（称为<strong>解码（Decode）</strong> 阶段）显著提速。</p><h2 id="二、kv-cache" tabindex="-1">二、KV Cache <a class="header-anchor" href="#二、kv-cache" aria-label="Permalink to “二、KV Cache”">​</a></h2><p>为了生成下一个 Token，模型仍然需要依赖于先前所有 Token 的键（$K$）和值（$V$）投影结果。如果每次都从头计算，就会浪费大量的计算资源。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/simple_attention.png" alt="simple_attention.png" style="zoom:50%;"><p><strong>KV Cache</strong> 机制正是为了解决这个问题而设计的：它是一个存储了生成过程中所有先前 Token 的 $K$ 和 $V$ 状态的列表。通过重用这些缓存的状态，生成 Token $n+1$ 的计算成本可以从预填充阶段的 $O(n^2)$ 降低到解码阶段的 $O(n)$，代价是 $O(n)$ 的内存开销。</p><h3 id="_1-缓存大小计算" tabindex="-1">1. 缓存大小计算 <a class="header-anchor" href="#_1-缓存大小计算" aria-label="Permalink to “1. 缓存大小计算”">​</a></h3><p>对于一个拥有 $L$ 个注意力层、$H$ 个注意力头且头维度为 $A$ 的模型，存储一个 Token 所需的总缓存大小为：</p><p>$$ \\text{CacheSize}_{\\text{token}} = 2 \\times L \\times A \\times H \\times \\text{DtypeSize} $$ 其中，系数 $2$ 代表同时存储 $K$ 和 $V$。例如，对于 Llama-2-7B 模型（$L=32, H=32, A=128$），在 $\\text{float16}$ 精度下（$\\text{DtypeSize}=2 \\text{ Bytes}$），每层每个 Token 需要 $2 \\times 32 \\times 128 = 8,192$ 个值，总共占用 $16 \\text{ KB}$ 的内存。</p><h3 id="_2-分块预填充-chunked-prefill" tabindex="-1">2. 分块预填充（Chunked Prefill） <a class="header-anchor" href="#_2-分块预填充-chunked-prefill" aria-label="Permalink to “2. 分块预填充（Chunked Prefill）”">​</a></h3><p>在实际应用中，初始提示词的长度 $n$ 可能会非常大（例如，将代码库作为上下文输入）。如果存储 $n$ 个 Token 的激活值所需的显存超过了 GPU 的可用显存，我们就无法在一次前向传播中完成预填充。此时，我们必须将预填充操作拆分为多个<strong>块（chunks）</strong>，这被称为<strong>分块预填充（Chunked Prefill）</strong>。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/chunked_prefill.png" alt="chunked prefill.png" style="zoom:33%;"><p>假设可用内存限制每次前向传播只能处理 $m$ 个 Token。对于一个 $n=7$ 个 Token 的提示词，如果 $m=4$，我们就需要 $\\lceil n/m \\rceil = 2$ 个块。</p><p>利用 KV 缓存，我们可以增量地处理提示词：</p><ol><li>在第一个块的预填充过程中，计算并存储 KV 状态。</li><li>在处理第二个块时，将已缓存的 KV 状态<strong>前置 (prepend)</strong> 到新的 KV 状态中，并相应地调整注意力掩码。</li></ol><p><strong>核心洞察</strong>：KV 缓存使得我们能够灵活地将预填充拆分成任意大小的块，以适应不同的内存限制，而不会丢失任何信息。</p><h2 id="三、连续批处理-continuous-batching-的优化" tabindex="-1">三、连续批处理（Continuous Batching）的优化 <a class="header-anchor" href="#三、连续批处理-continuous-batching-的优化" aria-label="Permalink to “三、连续批处理（Continuous Batching）的优化”">​</a></h2><p>在模型服务场景中，我们的目标是同时为多个用户的请求生成 Token，即最大化<strong>吞吐量</strong>（每秒生成的 Token 数）。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/padding.png" alt="padding.png" style="zoom:33%;"><h3 id="_1-朴素批处理的局限性" tabindex="-1">1. 朴素批处理的局限性 <a class="header-anchor" href="#_1-朴素批处理的局限性" aria-label="Permalink to “1. 朴素批处理的局限性”">​</a></h3><p>将多个提示词批处理在一起的<strong>朴素方法（Naïve Method）</strong> 是在输入张量中增加一个<strong>批次维度（Batch Dimension）</strong>。然而，这要求批次中的所有提示词必须具有相同的序列长度，因为张量必须是矩形的。为了满足这一要求，短序列通常需要通过<strong>填充（padding）</strong> 到最长序列的长度。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/batched_generation.png" alt="batched_generation.png" style="zoom:33%;"><p>这种<strong>批处理生成（Batched Generation）</strong> 在所有序列长度相同时是高效的，但在长度变化时会造成极大的浪费：</p><ul><li><strong>填充浪费：</strong> 当一个请求生成了特殊的 <code>&lt;eos&gt;</code>（End Of Sequence）Token 完成其生成时，它所占用的空间在批次中会持续浪费，直到批次中最长的请求完成。</li></ul><p>虽然可以通过<strong>动态调度（Dynamic Scheduling）</strong> 来解决第一个问题（将已完成的请求替换为新的等待请求），但这又引入了新的填充问题：新插入的请求需要进行预填充，而批次中的其他请求正在进行解码。新请求的全部长度几乎全部转化为填充 Token，造成巨大的计算浪费。</p><p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/dynamic_batching.png" alt="dynamic_batching.png"></p><p><strong>问题总结：</strong> 填充成本随着批大小 $B$ 和提示词长度 $n$ 呈<strong>二次方</strong>增长。此外，像 CUDA graphs 等优化技术需要静态张量形状，这迫使我们将所有提示词填充到固定的最大长度，进一步加剧了浪费。</p><h3 id="_2-参差批处理-ragged-batching" tabindex="-1">2. 参差批处理（Ragged Batching） <a class="header-anchor" href="#_2-参差批处理-ragged-batching" aria-label="Permalink to “2. 参差批处理（Ragged Batching）”">​</a></h3><p>连续批处理的关键在于<strong>彻底消除批次维度</strong>及其带来的填充问题。如果移除批次维度，将提示词批处理在一起的唯一方法就是将它们的 Token 序列<strong>拼接（concatenate）</strong> 起来，形成一个超长的单序列。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/concatenate.png" alt="concatenate.png" style="zoom:33%;"><p>这种将长度不均匀的序列拼接在一起的方式被称为<strong>参差批处理（Ragged Batching）</strong>。它的核心优势在于<strong>彻底消除了填充 Token</strong>，显著提高了吞吐量。</p><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/ragged_batching.png" alt="ragged_batching.png" style="zoom:33%;"><p>然而，拼接序列带来了一个问题：我们必须确保&quot;提示词 0&quot;的 Token 不会与&quot;提示词 1&quot;的 Token 进行交互。幸运的是，我们已经有工具来控制这种交互——<strong>注意力掩码</strong>。通过精心设计的注意力掩码，我们可以将所有请求的 Token 合并在一个批次中进行处理，同时确保因果关系和跨请求的隔离。</p><h3 id="_3-连续批处理的完整算法" tabindex="-1">3. 连续批处理的完整算法 <a class="header-anchor" href="#_3-连续批处理的完整算法" aria-label="Permalink to “3. 连续批处理的完整算法”">​</a></h3><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/continuous_batching/continuous_batching.png" alt="continuous_batching.png" style="zoom:33%;"><p><strong>连续批处理（Continuous Batching）</strong> 是参差批处理和动态调度的结合，旨在最大化 GPU 的内存和计算资源利用率。其调度算法的核心逻辑如下：</p><ol><li><strong>确定内存预算 $m$：</strong> 始终以达到每批次总 Token 数 $m$ 的内存预算为目标。</li><li><strong>优先解码序列：</strong> 首先将所有处于<strong>解码阶段</strong>（每个只占用 1 个 Token）的请求添加到当前批次中。</li><li><strong>填充预填充序列：</strong> 利用<strong>分块预填充</strong>的灵活性，用处于<strong>预填充阶段</strong>的请求来填充批次的剩余空间。如果一个预填充请求的长度过长，则根据剩余容量将其拆分为合适的块。</li><li><strong>动态调度：</strong> 一旦批次中的任一请求完成生成（生成 <code>&lt;eos&gt;</code>），立即将其从批次中移除，并用一个新的、等待处理的请求（以其第一个预填充块的形式）替换它。</li></ol><p>通过在同一批次中高效地混合预填充和解码阶段，并结合动态调度和无填充的参差批处理，连续批处理显著提高了 LLM 服务系统的效率。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to “结论”">​</a></h2><p><strong>连续批处理</strong>是现代高性能 LLM 服务系统的核心技术，它巧妙地结合了以下三种关键技术以最大化吞吐量：</p><ul><li><strong>KV Cache</strong>：避免在自回归生成过程中重复计算过去的 Token 表示。</li><li><strong>分块预填充（Chunked Prefill）</strong>：允许模型在内存受限的情况下，灵活、增量地处理可变且超长的提示词。</li><li><strong>参差批处理与动态调度（Ragged Batching &amp; Dynamic Scheduling）</strong>：通过消除批次维度和填充，以及动态替换已完成请求，确保 GPU 始终处于高负载运行状态。</li></ul><p>这种技术上的突破允许服务（如 ChatGPT）能够以高效率和低延迟同时处理成千上万的并发用户请求。</p>',66)])])}const d=t(g,[["render",i]]);export{u as __pageData,d as default};
